/* Suggested markup: <div class="uiwiki-margin-rail-quote" tabindex="0"><span>Margin Rail Quote</span></div> */
.uiwiki-margin-rail-quote {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-margin-rail-quote > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #53e8d4;
  animation: margin_rail_quote 1.8s ease-in-out infinite alternate;
}
.uiwiki-margin-rail-quote:hover,
.uiwiki-margin-rail-quote:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes margin_rail_quote {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-margin-rail-quote, .uiwiki-margin-rail-quote > span { animation: none; transition: none; }
}
